Here's how to test `DataFetcher` with modern MSTest patterns covering async, timeouts, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // Helper: creates an HttpClient backed by a custom handler
    private static HttpClient CreateClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new FakeHandler(handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var expected = """{"id":1,"name":"test"}""";
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent(expected),
            }));
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com/api", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        // Arrange
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.NotFound)));
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        using var client = CreateClient((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();       // honour the token
            return Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        });
        var fetcher = new DataFetcher(client);
        cts.Cancel();                                // cancel before calling

        // Act & Assert
        await Assert.ThrowsExactlyAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/api", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_ForwardsCancellationTokenToHttpClient()
    {
        // Arrange — capture the token the handler receives
        CancellationToken receivedToken = default;
        using var cts = new CancellationTokenSource();
        using var client = CreateClient((_, ct) =>
        {
            receivedToken = ct;
            return Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("ok"),
            });
        });
        var fetcher = new DataFetcher(client);

        // Act
        await fetcher.FetchAsync("https://example.com/api", cts.Token);

        // Assert — the exact token is forwarded
        Assert.AreEqual(cts.Token, receivedToken);
    }

    // Minimal HttpMessageHandler stub
    private sealed class FakeHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> onSend)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => onSend(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Sealed class** | `public sealed class` — best practice for test classes |
| **Constructor-injected TestContext** | Gives access to `_testContext.CancellationToken` (MSTest 3.6+) |
| **`[Timeout]` + `CancellationToken`** | `[Timeout(5000)]` auto-cancels via `TestContext.CancellationToken` if the test hangs |
| **Async exception testing** | `Assert.ThrowsExactlyAsync<T>` — no `[ExpectedException]` needed |
| **Cancellation verification** | Dedicated test that the token is forwarded, plus a pre-cancelled token test |
| **No external mocking library** | `FakeHandler` stubs `HttpMessageHandler.SendAsync` directly |

The `[Timeout]` attribute is critical for async tests — without it, a hung `await` blocks the test runner indefinitely. Passing `_testContext.CancellationToken` ensures the timeout actually cancels your async call chain.
